"use strict";(globalThis.webpackChunkbitcoin_junioren=globalThis.webpackChunkbitcoin_junioren||[]).push([[851],{6851(e){e.exports=JSON.parse('{"ui":{"greeting":"Ahoy, {name}! \ud83c\udff4\u200d\u2620\ufe0f","title":"Bitcoin per Ragazzi","subtitle":"Scopri il mondo del denaro, del valore e di Bitcoin!","progress":"Progresso","newPlayer":"Inizia nuovo giocatore","newPlayerConfirm":"Iniziare con un nuovo giocatore? Il progresso attuale verr\xe0 cancellato.","footer":"Basato su Bitcoin per Ragazzi di My First Bitcoin \xb7 CC BY-SA 4.0","nameScreen":{"title":"Ahoy, avventuriero!","subtitle":"Come ti chiami?","placeholder":"Il tuo nome...","button":"Inizia l\'avventura! \ud83d\ude80"},"activity":{"back":"\u2190 Indietro","next":"Avanti \u2192","finish":"Fatto! \ud83c\udf89","correct":"Corretto!","wrong":"Sbagliato","score":"Punteggio","tryAgain":"Riprova","completed":"Completato!","badgeEarned":"Distintivo guadagnato!"},"sort":{"instruction":"Trascina dal pi\xf9 economico al pi\xf9 caro","check":"Controlla l\'ordine"},"categorize":{"instruction":"Trascina nella categoria giusta"},"match":{"instruction":"Abbina le coppie"},"truefalse":{"public":"Pubblico","private":"Privato"},"cipher":{"instruction":"Decifra il codice con la ruota cifrata"},"mining":{"instruction":"Trova le coppie uguali"},"scramble":{"instruction":"Ricomponi la parola","hint":"Suggerimento"},"moduleView":{"back":"\u2190 Indietro","map":"\u2190 Mappa del tesoro","coreIdea":"\ud83d\udca1 Idea chiave","activities":"Attivit\xe0","module":"Modulo"},"activityTypes":{"quiz":"Quiz","sort":"Ordina","match":"Abbina","cipher":"Decifra codici","mining":"Memory","truefalse":"Pubblico/Privato","categorize":"Categorizza","scramble":"Rimescolatore di parole"}},"modules":[{"id":1,"title":"Scambio, Valore e Prezzo","icon":"\u2693","color":"#D97706","bg":"#FEF3C7","summary":"Il valore dipende da ci\xf2 di cui hai bisogno. Il prezzo \xe8 quanto costa qualcosa. Il denaro risolve il problema del baratto.","description":"Scopri perch\xe9 usiamo il denaro e cosa valgono davvero le cose!","badge":"\ud83c\udfdd\ufe0f Commerciante dell\'isola","activities":[{"type":"quiz","title":"Sopravvivere sull\'isola","intro":"Sei un naufrago su un\'isola deserta!","questions":[{"q":"Arrivi su un\'isola deserta. Cosa vale di pi\xf9?","options":["\ud83d\udc8e Diamante","\ud83d\udd2a Un machete","\ud83d\udcf1 Smartphone","\ud83d\udcb0 100 euro"],"correct":1,"explanation":"Su un\'isola, con un machete puoi tagliare legna, preparare il cibo e costruire un riparo. Denaro e diamanti l\xec non servono a niente!"},{"q":"Hai 5 canne da pesca ma nessuna tenda. Il tuo vicino ha 3 tende ma nessuna canna. Cosa fate?","options":["Aspettate entrambi","Scambiate: una canna da pesca per una tenda!","Niente, sfortuna","Piangete insieme"],"correct":1,"explanation":"Lo scambio \xe8 il modo pi\xf9 antico di fare commercio! Dai quello che hai in eccesso per ottenere quello di cui hai bisogno."},{"q":"Perch\xe9 il baratto \xe8 a volte molto difficile?","options":["Perch\xe9 \xe8 noioso","Perch\xe9 devi trovare qualcuno che voglia esattamente quello che hai tu","Perch\xe9 \xe8 vietato","Perch\xe9 le cose sono troppo pesanti"],"correct":1,"explanation":"Questo si chiama \'doppia coincidenza dei bisogni\'. Il denaro risolve questo problema \u2014 tutti accettano il denaro!"},{"q":"In passato le conchiglie venivano usate come denaro. Cosa rende qualcosa un buon denaro?","options":["Deve essere bello","Deve essere scarso, portabile e accettato da tutti","Deve essere commestibile","Deve venire dal governo"],"correct":1,"explanation":"Un buon denaro \xe8 scarso (non infinito), facile da portare con s\xe9, e tutti devono accettarlo come pagamento."},{"q":"Una bottiglia d\'acqua costa \u20ac1 al supermercato. Nel deserto qualcuno ti offre \u20ac100 per la stessa bottiglia. Perch\xe9?","options":["Il negozio era pi\xf9 caro","Perch\xe9 l\'acqua nel deserto \xe8 molto pi\xf9 scarsa e importante","\xc8 un\'acqua diversa","Il deserto \xe8 lontano"],"correct":1,"explanation":"La scarsit\xe0 cambia il valore! Meno ce n\'\xe8 di qualcosa e pi\xf9 ne hai bisogno, pi\xf9 diventa preziosa."},{"q":"Qual \xe8 la differenza tra prezzo e valore?","options":["Non c\'\xe8 differenza","Il prezzo \xe8 quanto costa qualcosa, il valore \xe8 quanto \xe8 importante per te","Il prezzo \xe8 sempre pi\xf9 alto del valore","Il valore riguarda solo il denaro"],"correct":1,"explanation":"Un disegno fatto da tuo figlio potrebbe non avere un prezzo, ma ha un valore enorme. Prezzo e valore non sono la stessa cosa!"}]},{"type":"sort","title":"La linea dei prezzi","intro":"Metti gli oggetti nell\'ordine giusto, dal pi\xf9 economico al pi\xf9 caro!","items":[{"name":"\ud83c\udf4e Mela","value":1},{"name":"\ud83d\udcd6 Libro","value":2},{"name":"\u26bd Pallone da calcio","value":3},{"name":"\ud83d\udcf1 Telefono","value":4},{"name":"\ud83d\udef5 Scooter","value":5},{"name":"\ud83c\udfe0 Casa","value":6}]}]},{"id":2,"title":"Tempo, Energia e Ricompensa","icon":"\u26a1","color":"#0D9488","bg":"#CCFBF1","summary":"L\'energia \xe8 limitata. L\'equilibrio tra lavoro, riposo e gioco \xe8 importante. La pazienza porta a risultati migliori.","description":"Come usi il tuo tempo e la tua energia? E perch\xe9 aspettare \xe8 a volte pi\xf9 furbo?","badge":"\u23f3 Maestro del tempo","activities":[{"type":"categorize","title":"Lavoro, Riposo o Gioco?","intro":"Trascina ogni attivit\xe0 nella categoria giusta!","categories":["\ud83d\udcbc Lavoro","\ud83d\ude34 Riposo","\ud83c\udfae Gioco"],"items":[{"name":"Fare i compiti","cat":0},{"name":"Dormire","cat":1},{"name":"Giocare a calcio","cat":2},{"name":"Riordinare la camera","cat":0},{"name":"Leggere un libro","cat":1},{"name":"Giocare a rincorrersi","cat":2},{"name":"Apparecchiare la tavola","cat":0},{"name":"Fare un pisolino","cat":1},{"name":"Giocare ai videogiochi","cat":2},{"name":"Fare la spesa","cat":0},{"name":"Ascoltare musica","cat":1},{"name":"Andare al parco giochi","cat":2}]},{"type":"quiz","title":"Preferenza temporale","intro":"Scegli tu: ORA o PI\xd9 TARDI?","questions":[{"q":"Nella storia dei tre porcellini: quale casa rimase in piedi?","options":["\ud83c\udf3e Paglia (costruita in fretta)","\ud83e\udeb5 Legno (via di mezzo)","\ud83e\uddf1 Mattoni (ci volle pi\xf9 tempo)"],"correct":2,"explanation":"La casa di mattoni richiedeva pi\xf9 tempo e fatica, ma era l\'unica che rimase in piedi. La pazienza paga!"},{"q":"Cosa significa \'bassa preferenza temporale\'?","options":["Vuoi tutto ORA","Sei disposto ad aspettare qualcosa di meglio","Non hai un orologio","Dormi molto"],"correct":1,"explanation":"Bassa preferenza temporale = essere disposti ad aspettare per un risultato migliore. Come il porcellino che costru\xec la casa di mattoni!"},{"q":"Ricevi 1 caramella adesso, oppure 3 caramelle se aspetti 10 minuti. Qual \xe8 la scelta pi\xf9 furba?","options":["1 caramella ADESSO!","Aspettare: 3 caramelle > 1 caramella","Le caramelle fanno male","Scappare"],"correct":1,"explanation":"Questo \xe8 il famoso test del marshmallow! I bambini che riuscivano ad aspettare spesso ottenevano risultati migliori a scuola."},{"q":"Hai un\'interrogazione importante domani. Cosa rappresenta la bassa preferenza temporale?","options":["Giocare ora e studiare domani","Studiare oggi cos\xec domani vai bene","Saltare l\'interrogazione","Sperare nella fortuna"],"correct":1,"explanation":"Fare qualcosa di difficile ora (studiare) per ottenere qualcosa di buono dopo (un bel voto) \u2014 questa \xe8 la bassa preferenza temporale."},{"q":"Cosa succede se esaurisci tutta la tua energia al mattino?","options":["Diventi pi\xf9 forte","Non ti resta nulla per il resto della giornata","Ottieni superpoteri","Niente di speciale"],"correct":1,"explanation":"L\'energia \xe8 limitata! Distribuirla con intelligenza \xe8 importante \u2014 proprio come il denaro."}]}]},{"id":3,"title":"Analogico contro Digitale","icon":"\ud83d\udd04","color":"#7C3AED","bg":"#EDE9FE","summary":"La tecnologia cambia continuamente. Ogni invenzione risolve un problema. Non tutto ci\xf2 che \xe8 nuovo \xe8 automaticamente migliore.","description":"Dal piccione viaggiatore a internet \u2014 come la tecnologia cambia il mondo!","badge":"\ud83d\ude80 Pioniere della tecnologia","activities":[{"type":"match","title":"Vecchio \u2194 Nuovo","intro":"Abbina ogni vecchia tecnologia alla sua versione moderna!","pairs":[{"old":"\u2709\ufe0f Lettera","new":"\ud83d\udce7 E-mail"},{"old":"\ud83d\udcde Telefono a rotella","new":"\ud83d\udcf1 Smartphone"},{"old":"\ud83d\uddfa\ufe0f Cartina cartacea","new":"\ud83d\udccd GPS"},{"old":"\ud83d\udcf7 Rullino fotografico","new":"\ud83d\udcf8 Fotocamera digitale"},{"old":"\ud83d\udcf0 Giornale","new":"\ud83c\udf10 Sito di notizie"},{"old":"\ud83d\udcb0 Monete","new":"\u20bf Bitcoin"}]},{"type":"quiz","title":"Immagina il futuro","intro":"Come sar\xe0 la tecnologia tra 20 anni?","questions":[{"q":"Perch\xe9 le tecnologie cambiano nel tempo?","options":["Perch\xe9 le cose vecchie si rompono","Perch\xe9 le persone risolvono problemi con nuove invenzioni","Perch\xe9 lo vuole il governo","Senza motivo"],"correct":1,"explanation":"Ogni invenzione risolve un problema. L\'automobile ha risolto il problema che i cavalli si stancano e sono lenti!"},{"q":"La nuova tecnologia \xe8 SEMPRE migliore di quella vecchia?","options":["S\xec, sempre","No, a volte quella vecchia \xe8 migliore o pi\xf9 affidabile","La nuova tecnologia non esiste","Solo se costa di pi\xf9"],"correct":1,"explanation":"Un libro cartaceo non ha bisogno di batterie! A volte le soluzioni vecchie sono ancora ottime."},{"q":"Bitcoin \xe8 denaro digitale. Cosa ha in comune con le antiche conchiglie?","options":["Entrambi vengono dal mare","Entrambi sono scarsi e usati come mezzo di scambio","Niente","Entrambi sono gratuiti"],"correct":1,"explanation":"Sia le conchiglie che Bitcoin sono scarsi (ce n\'\xe8 una quantit\xe0 limitata) e vengono usati come mezzo di scambio."},{"q":"Cos\'\xe8 l\'innovazione?","options":["Comprare qualcosa di nuovo","Un miglioramento o un\'invenzione intelligente che risolve un problema","Una parola difficile che non significa nulla","Solo per gli scienziati"],"correct":1,"explanation":"Innovazione = una soluzione nuova o migliore per un problema esistente. Tutti possono innovare!"}]}]},{"id":4,"title":"Sicurezza e Privacy","icon":"\ud83d\udee1\ufe0f","color":"#DC2626","bg":"#FEE2E2","summary":"Sei tu a decidere quali informazioni condividi. I codici proteggono i messaggi. La fiducia non \xe8 sempre necessaria se hai la crittografia.","description":"Codici segreti, privacy e come proteggerti online!","badge":"\ud83d\udd10 Cypherpunk","activities":[{"type":"truefalse","title":"Pubblico o Privato?","intro":"Questa informazione \xe8 pubblica o privata? Decidi in fretta!","statements":[{"text":"La tua password","answer":false,"label":"Privato!","explanation":"Una password \xe8 sempre privata. Non condividerla mai!"},{"text":"Il tuo nome a scuola","answer":true,"label":"Pubblico","explanation":"A scuola tutti sanno come ti chiami \u2014 \xe8 un\'informazione pubblica."},{"text":"Il tuo PIN","answer":false,"label":"Privato!","explanation":"Il tuo PIN \xe8 segreto \u2014 protegge il tuo conto in banca."},{"text":"Un parco in citt\xe0","answer":true,"label":"Pubblico","explanation":"Un parco \xe8 un luogo pubblico \u2014 tutti possono andarci."},{"text":"Il tuo diario","answer":false,"label":"Privato!","explanation":"Il tuo diario \xe8 privato \u2014 solo tu decidi chi pu\xf2 leggerlo."},{"text":"Il colore della tua bici","answer":true,"label":"Pubblico","explanation":"Tutti possono vedere di che colore \xe8 la tua bici."},{"text":"Il tuo indirizzo di casa","answer":false,"label":"Privato!","explanation":"Non dare il tuo indirizzo agli sconosciuti \u2014 \xe8 un\'informazione privata."},{"text":"Il tempo oggi","answer":true,"label":"Pubblico","explanation":"Il tempo \xe8 uguale per tutti \u2014 completamente pubblico!"},{"text":"La tua chiave Bitcoin","answer":false,"label":"Privato!","explanation":"La tua chiave privata \xe8 il segreto pi\xf9 importante. Chi ce l\'ha, ha i tuoi bitcoin!"}]},{"type":"cipher","title":"Codice segreto","intro":"Decifra le parole segrete di Bitcoin con la ruota cifrata!"}]},{"id":5,"title":"Questioni di denaro","icon":"\ud83c\udfe6","color":"#B45309","bg":"#FEF3C7","summary":"Il denaro pu\xf2 essere guadagnato, risparmiato, investito e speso. Fare un budget significa fare scelte. Le regole giuste sono importanti.","description":"Guadagnare, risparmiare, investire \u2014 diventa un esperto di denaro!","badge":"\ud83d\udc8e Saggio del denaro","activities":[{"type":"quiz","title":"Intelligente con il denaro","intro":"Metti alla prova la tua intelligenza finanziaria!","questions":[{"q":"Cos\'\xe8 il risparmio?","options":["Spendere subito il denaro","Mettere da parte il denaro per dopo","Buttare via il denaro","Prendere in prestito denaro da un amico"],"correct":1,"explanation":"Risparmiare = conservare il denaro per poter comprare qualcosa di pi\xf9 grande o importante in futuro."},{"q":"Cos\'\xe8 investire?","options":["Nascondere il denaro","Mettere il tuo denaro o il tuo tempo in qualcosa affinch\xe9 valga di pi\xf9 in futuro","Spendere tutto oggi","Bruciare il denaro"],"correct":1,"explanation":"Investire significa mettere il tuo denaro o il tuo tempo in qualcosa con la speranza che in futuro valga di pi\xf9."},{"q":"Hai 12 conchiglie. Una tenda costa 8 e una canna da pesca costa 6. Puoi comprarle entrambe?","options":["S\xec!","No, 8 + 6 = 14, ma ne hai solo 12","Solo con lo sconto","Le conchiglie non sono denaro"],"correct":1,"explanation":"8 + 6 = 14, ma hai solo 12 conchiglie. Devi scegliere! Questo si chiama fare un budget."},{"q":"A un\'asta il prezzo di un oggetto raro continua a salire. Perch\xe9?","options":["Il venditore \xe8 cattivo","Molte persone lo vogliono, ma ce n\'\xe8 solo uno (scarsit\xe0 + domanda)","L\'oggetto diventa sempre pi\xf9 grande","Perch\xe9 qualcuno bara"],"correct":1,"explanation":"Quando molte persone vogliono qualcosa ma ce n\'\xe8 poco, il prezzo sale. Cos\xec funziona la domanda e l\'offerta!"},{"q":"Perch\xe9 le regole giuste sono importanti con il denaro?","options":["Non lo sono","Perch\xe9 tutti abbiano le stesse opportunit\xe0","Solo per i bambini","Per rendere tutto pi\xf9 difficile"],"correct":1,"explanation":"Le regole giuste garantiscono che nessuno possa barare e che tutti abbiano le stesse possibilit\xe0."},{"q":"Cos\'\xe8 un prestito?","options":["Rubare denaro","Ricevere denaro da qualcun altro che devi restituire in seguito","Risparmiare denaro","Perdere denaro"],"correct":1,"explanation":"Un prestito significa ricevere denaro da qualcun altro, ma doverlo restituire in seguito \u2014 spesso con qualcosa in pi\xf9 (gli interessi)."}]}]},{"id":6,"title":"Principi base di Bitcoin","icon":"\u20bf","color":"#EA580C","bg":"#FFF7ED","summary":"Bitcoin \xe8 denaro digitale scarso senza intermediari. Il mining conferma le transazioni. Satoshi \xe8 rimasto anonimo.","description":"La grande avventura di Bitcoin: da Satoshi al mining!","badge":"\u26cf\ufe0f Miner di Bitcoin","activities":[{"type":"quiz","title":"Chi \xe8 Satoshi?","intro":"Scopri la storia dietro Bitcoin!","questions":[{"q":"Chi ha inventato Bitcoin?","options":["Elon Musk","Satoshi Nakamoto","La banca","Google"],"correct":1,"explanation":"Satoshi Nakamoto ha pubblicato nel 2008 un \'white paper\' con l\'idea di Bitcoin. Nessuno sa chi sia veramente Satoshi!"},{"q":"Cos\'\xe8 un \'white paper\'?","options":["Un foglio bianco","Un documento in cui si spiega una nuova idea","Una lettera segreta","Un compito scolastico"],"correct":1,"explanation":"Un white paper \xe8 un documento in cui si presenta al mondo una nuova idea o soluzione."},{"q":"Cos\'\xe8 il Blocco Genesi?","options":["Un videogioco","Il primissimo blocco di Bitcoin","Un tipo di pietra","Una password segreta"],"correct":1,"explanation":"Il 3 gennaio 2009 fu creato il Blocco Genesi \u2014 il primo blocco nella blockchain di Bitcoin."},{"q":"Quanti bitcoin esisteranno mai?","options":["Infiniti","Al massimo 21 milioni","Esattamente 1 miliardo","Nessuno lo sa"],"correct":1,"explanation":"Non esisteranno mai pi\xf9 di 21 milioni di bitcoin. Questa scarsit\xe0 \xe8 integrata nelle regole!"},{"q":"Cosa significa \'minare\' Bitcoin?","options":["Scavare nel terreno","Usare computer per risolvere enigmi e confermare le transazioni","Stampare bitcoin","Disegnare bitcoin"],"correct":1,"explanation":"I miner usano computer per risolvere enigmi matematici. Come prova del lavoro svolto, possono confermare le transazioni."},{"q":"Cos\'\xe8 la Proof of Work?","options":["Una pagella scolastica","La prova che qualcuno ha davvero lavorato per guadagnarsi qualcosa","Una password","Una specie di diploma"],"correct":1,"explanation":"Proof of Work = prova del lavoro. Come nel gioco dei dadi: tutti seguono le stesse regole e hanno le stesse possibilit\xe0."},{"q":"Perch\xe9 Satoshi \xe8 sparito?","options":["\xc8 andato in vacanza","Probabilmente per far s\xec che Bitcoin appartenesse davvero a tutti, senza un leader","Si \xe8 arrabbiato","Non esiste"],"correct":1,"explanation":"Sparendo, Satoshi ha fatto in modo che Bitcoin non appartenesse a nessuna persona. La rete funziona grazie alle regole, non a un leader."}]},{"type":"mining","title":"Mina Bitcoin!","intro":"Trova le coppie uguali per minare blocchi \u2014 proprio come i veri miner!"},{"type":"scramble","title":"Rimescolatore di parole Bitcoin","intro":"Ricomponi le parole di Bitcoin mescolate!","words":[{"scrambled":"COINBIT","answer":"BITCOIN","hint":"Denaro digitale"},{"scrambled":"SHATISO","answer":"SATOSHI","hint":"Il misterioso inventore"},{"scrambled":"COBLO","answer":"BLOCCO","hint":"Le transazioni sono contenute qui"},{"scrambled":"RASCO","answer":"SCARSO","hint":"Ce n\'\xe8 pochissimo"},{"scrambled":"ARMINE","answer":"MINARE","hint":"Risolvere enigmi con i computer"},{"scrambled":"TLETOW","answer":"WALLET","hint":"Qui conservi i tuoi bitcoin"}]}]}]}')}}]);